import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions } from '../../../includes';
import { routeNamesSchool } from '../../routeNames';



const style = theme => ({
    root: {
    }
})
class _Payroll extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "ACCOUNT (PAYROLL)"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Account (Payroll)", path : routeNamesSchool.accountPayroll},
        ])(dispatch);
    }
    
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                This is the pay roll
            </div>
        );
    }
}


_Payroll.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Payroll = connect(mapStateToProps)(withStyles(style)(_Payroll));
export {Payroll as default}